return; // TODO: Serialize Governor state const state = { missionId: activeMission.id, timestamp: Date.now() // Add Governor state here }; await saveCheckpoint(activeMission.id, state); logger.debug(`Checkpoint created for mission ${activeMission.id}`); } catch (error) { logger.error('Failed to create checkpoint:', error); } } /** * Handle service worker suspension */ chrome.runtime.onSuspend.addListener(async () => { logger.warn('Service worker suspending, saving state...'); // Clear intervals if (keepaliveInterval) clearInterval(keepaliveInterval); if (checkpointInterval) clearInterval(checkpointInterval);

