/**
 * Throttle function
 */
export function throttle<T extends (...args: unknown[]) => unknown>(
  fn: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;

  return (...args: Parameters<T>) => {
    if (!inThrottle) {
      fn(...args);
      inThrottle = true;
      setTimeout(() => (inThrottle = false), limit);
    }
  };
}

import { db } from './db';
import type { Checkpoint } from '@/shared/types';
import { loggers } from '@/shared/logger';
import { generateId } from '@/shared/utils';

const logger = loggers.storage;

/**
 * Save checkpoint (service worker state before suspension)
 */
export async function saveCheckpoint(
  missionId: string,
  state: unknown
): Promise<Checkpoint> {
  const checkpoint: Checkpoint = {
    id: generateId(),
    missionId,
    state,
    timestamp: Date.now()
  };

  await db.checkpoints.add(checkpoint);
  logger.debug(`Checkpoint saved for mission ${missionId}`);
  return checkpoint;
}

/**
 * Get latest checkpoint for mission
 */
export async function getLatestCheckpoint(
  missionId: string
): Promise<Checkpoint | undefined> {
  const checkpoints = await db.checkpoints
    .where('missionId')
    .equals(missionId)
    .sortBy('timestamp');

  return checkpoints.length > 0 ? checkpoints[checkpoints.length - 1] : undefined;
}

/**
 * List all checkpoints for mission
 */
export async function listCheckpoints(
  missionId: string
): Promise<Checkpoint[]> {
  return db.checkpoints
    .where('missionId')
    .equals(missionId)
    .reverse()
    .toArray();
}

/**
 * Delete old checkpoints (keep last N per mission)
 */
export async function pruneCheckpoints(
  missionId: string,
  keepLast: number = 5
): Promise<number> {
  const checkpoints = await listCheckpoints(missionId);

  if (checkpoints.length <= keepLast) {
    return 0;
  }

  const toDelete = checkpoints.slice(keepLast);
  const ids = toDelete.map(c => c.id);

  await db.checkpoints.bulkDelete(ids);
  logger.debug(`Pruned ${ids.length} checkpoints for mission ${missionId}`);
  return ids.length;
}

/**
 * Delete all checkpoints for mission
 */
export async function deleteCheckpoints(missionId: string): Promise<void> {
  await db.checkpoints.where('missionId').equals(missionId).delete();
  logger.debug(`Deleted all checkpoints for mission ${missionId}`);
}

import Dexie, { type Table } from 'dexie';
import type { Mission, Checkpoint, MemoryEntry } from '@/shared/types';
import { loggers } from '@/shared/logger';

const logger = loggers.storage;

/**
 * IndexedDB schema for Alpha Browser
 * Stores missions, checkpoints, and long-term memory
 */
export class AlphaDB extends Dexie {
  missions!: Table<Mission, string>;
  checkpoints!: Table<Checkpoint, string>;
  memory!: Table<MemoryEntry, string>;

  constructor() {
    super('AlphaBrowserDB');

    this.version(1).stores({
      missions: 'id, status, createdAt, updatedAt',
      checkpoints: 'id, missionId, timestamp',
      memory: 'id, missionId, timestamp, tags'
    });
  }
}

// Singleton instance
export const db = new AlphaDB();

/**
 * Initialize database and run migrations
 */
export async function initDB(): Promise<void> {
  try {
    await db.open();
    logger.info('Database initialized successfully');
  } catch (error) {
    logger.error('Failed to initialize database:', error);
    throw error;
  }
}

/**
 * Clear all data (for testing)
 */
export async function clearDB(): Promise<void> {
  await db.missions.clear();
  await db.checkpoints.clear();
  await db.memory.clear();
  logger.info('Database cleared');
}

/**
 * Get database statistics
 */
export async function getDBStats(): Promise<{
  missions: number;
  checkpoints: number;
  memory: number;
}> {
  return {
    missions: await db.missions.count(),
    checkpoints: await db.checkpoints.count(),
    memory: await db.memory.count()
  };
}

import { db } from './db';
import type { MemoryEntry } from '@/shared/types';
import { loggers } from '@/shared/logger';
import { generateId } from '@/shared/utils';

const logger = loggers.storage;

/**
 * Store memory entry (for RAG future enhancement)
 */
export async function storeMemory(
  missionId: string,
  content: string,
  tags: string[] = []
): Promise<MemoryEntry> {
  const entry: MemoryEntry = {
    id: generateId(),
    missionId,
    content,
    tags,
    timestamp: Date.now()
  };

  await db.memory.add(entry);
  logger.debug(`Memory stored for mission ${missionId}`);
  return entry;
}

/**
 * Search memory by tags
 */
export async function searchMemoryByTags(
  tags: string[],
  limit: number = 10
): Promise<MemoryEntry[]> {
  return db.memory
    .filter(entry => tags.some(tag => entry.tags.includes(tag)))
    .limit(limit)
    .reverse()
    .toArray();
}

/**
 * Get memory for mission
 */
export async function getMissionMemory(
  missionId: string
): Promise<MemoryEntry[]> {
  return db.memory
    .where('missionId')
    .equals(missionId)
    .toArray();
}

/**
 * Delete old memory entries
 */
export async function pruneMemory(days: number = 90): Promise<number> {
  const cutoff = Date.now() - days * 24 * 60 * 60 * 1000;

  const toDelete = await db.memory
    .where('timestamp')
    .below(cutoff)
    .primaryKeys();

  await db.memory.bulkDelete(toDelete as string[]);
  logger.info(`Pruned ${toDelete.length} memory entries`);
  return toDelete.length;
}

import { db } from './db';
import type { Mission, MissionStatus } from '@/shared/types';
import { loggers } from '@/shared/logger';
import { generateId } from '@/shared/utils';

const logger = loggers.storage;

/**
 * Create a new mission
 */
export async function createMission(goal: string): Promise<Mission> {
  const mission: Mission = {
    id: generateId(),
    goal,
    status: 'pending',
    steps: [],
    createdAt: Date.now(),
    updatedAt: Date.now()
  };

  await db.missions.add(mission);
  logger.info(`Mission created: ${mission.id}`);
  return mission;
}

/**
 * Get mission by ID
 */
export async function getMission(id: string): Promise<Mission | undefined> {
  return db.missions.get(id);
}

/**
 * Update mission status
 */
export async function updateMissionStatus(
  id: string,
  status: MissionStatus
): Promise<void> {
  const updates: Partial<Mission> = {
    status,
    updatedAt: Date.now()
  };

  if (status === 'completed' || status === 'failed') {
    updates.completedAt = Date.now();
  }

  await db.missions.update(id, updates);
