createServiceClient() // Log the webhook event for debugging/replay await supabase.from('billing.webhook_events').insert({ event_id: event.event_id, event_type: event.event_type, payload: event, processed: false, }) try { switch (event.event_type) { case 'customer.created': case 'customer.updated': await handleCustomerEvent(event, supabase) break case 'subscription.created': case 'subscription.activated': await handleSubscriptionCreated(event, supabase) break case 'subscription.updated': await handleSubscriptionUpdated(event, supabase) break case 'subscription.canceled': await handleSubscriptionCanceled(event, supabase) break case 'transaction.completed': await handleTransactionCompleted(event, supabase) break case 'transaction.paid': await handleTransactionPaid(event, supabase) break

      default:
        console.log(`Unhandled event type: ${event.event_type}`)
    }

    // Mark event as processed
    await supabase
      .from('billing.webhook_events')
      .update({ processed: true, processed_at: new Date().toISOString() })
      .eq('event_id', event.event_id)

    return NextResponse.json({ received: true })
  } catch (error) {
