/**
 * Odoo JSON-RPC client for partner provisioning
 *
 * This module handles the creation/update of res.partner records in Odoo
 * when a new subscription is created via Paddle.
 */

interface OdooConfig {
  baseUrl: string
  db: string
  username: string
  password: string
}

interface OdooPartnerData {
  name: string
  email: string
  company_name?: string
  country_code?: string
  vat?: string
  phone?: string
  paddle_customer_id: string
  supabase_org_id: string
}

interface JsonRpcResponse<T = unknown> {
  jsonrpc: '2.0'
  id: number
  result?: T
  error?: {
    code: number
    message: string
    data: {
      name: string
      message: string
      debug: string
    }
  }
}

let sessionUid: number | null = null

async function jsonRpc<T>(
  url: string,
  method: string,
  params: Record<string, unknown>
): Promise<T> {
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      jsonrpc: '2.0',
      id: Date.now(),
      method: 'call',
      params: {
        service: method.split('.')[0],
        method: method.split('.')[1],
        args: params.args,
      },
    }),
  })

  const data: JsonRpcResponse<T> = await response.json()

  if (data.error) {
    throw new Error(`Odoo RPC Error: ${data.error.data?.message || data.error.message}`)
  }

  return data.result as T
}

async function authenticate(config: OdooConfig): Promise<number> {
  if (sessionUid) return sessionUid

  const result = await jsonRpc<number>(
    `${config.baseUrl}/jsonrpc`,
    'common.authenticate',
    {
      args: [config.db, config.username, config.password, {}],
    }
  )

  if (!result) {
    throw new Error('Odoo authentication failed')
  }

  sessionUid = result
  return result
}

async function execute<T>(
  config: OdooConfig,
  model: string,
  method: string,
  args: unknown[],
  kwargs: Record<string, unknown> = {}
): Promise<T> {
  const uid = await authenticate(config)

async function authenticate(config: OdooConfig): Promise<number> { if (sessionUid) return sessionUid const result = await jsonRpc<number>( `${config.baseUrl}/jsonrpc`, 'common.authenticate', { args: [config.db, config.username, config.password, {}], } ) if (!result) { throw new Error('Odoo authentication failed') } sessionUid = result return result } async function execute<T>( config: OdooConfig, model: string, method: string, args: unknown[], kwargs: Record<string, unknown> = {} ): Promise<T> { const uid = await authenticate(config)

  const response = await fetch(`${config.baseUrl}/jsonrpc`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      jsonrpc: '2.0',
      id: Date.now(),
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [config.db, uid, config.password, model, method, args, kwargs],
      },
    }),
  })

  const data: JsonRpcResponse<T> = await response.json()

  if (data.error) {
    throw new Error(`Odoo execute error: ${data.error.data?.message || data.error.message}`)
  }

  return data.result as T
}

