}

import crypto from 'crypto'

export interface PaddleWebhookEvent {
  event_id: string
  event_type: string
  occurred_at: string
  notification_id: string
  data: {
    id: string
    status: string
    customer_id: string
    address_id?: string
    business_id?: string
    currency_code: string
    items: Array<{
      price: {
        id: string
        product_id: string
        name: string
        unit_price: {
          amount: string
          currency_code: string
        }
      }
      quantity: number
    }>
    billing_period?: {
      starts_at: string
      ends_at: string
    }
    current_billing_period?: {
      starts_at: string
      ends_at: string
    }
    custom_data?: Record<string, string>
  }
}

export function verifyPaddleWebhookSignature(
  payload: string,
  signature: string,
  secret: string
): boolean {
  if (!signature || !secret) {
    return false
  }

  // Paddle uses ts;h1=<signature> format
  const parts = signature.split(';')
  const timestampPart = parts.find(p => p.startsWith('ts='))
  const signaturePart = parts.find(p => p.startsWith('h1='))

  if (!timestampPart || !signaturePart) {
    return false
  }

  const timestamp = timestampPart.replace('ts=', '')
  const expectedSignature = signaturePart.replace('h1=', '')

  // Reconstruct the signed payload
  const signedPayload = `${timestamp}:${payload}`

  // Calculate HMAC
  const hmac = crypto.createHmac('sha256', secret)
  hmac.update(signedPayload)
  const calculatedSignature = hmac.digest('hex')

  // Constant-time comparison
  try {
    return crypto.timingSafeEqual(
      Buffer.from(calculatedSignature, 'hex'),
      Buffer.from(expectedSignature, 'hex')
    )
  } catch {
    return false
  }
}

