  if (raw === '' || raw === 'home') return 'home';
  if (VALID_PAGES.includes(raw as PageId)) return raw as PageId;
  return 'home';
}

function hashFromPageId(page: PageId): string {
  return page === 'home' ? '' : `#${page}`;
}

