    private init() {}

    /// Upload a receipt image and extract structured data.
    /// - Parameters:
    ///   - image: The captured receipt photo.
    ///   - completion: Returns parsed `ReceiptData` or an error.
    func analyzeReceipt(_ image: UIImage, completion: @escaping (Result<ReceiptData, Error>) -> Void) {
        guard let imageData = image.jpegData(compressionQuality: 0.85) else {
            completion(.failure(OCRError.imageConversionFailed))
            return
        }

        var request = URLRequest(url: URL(string: endpoint)!)
        request.httpMethod = "POST"
        request.setValue("image/jpeg", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.timeoutInterval = 30

        let task = URLSession.shared.uploadTask(with: request, from: imageData) { data, response, error in
            if let error = error {
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            }

            guard let httpResponse = response as? HTTPURLResponse,
                  (200...299).contains(httpResponse.statusCode),
                  let data = data else {
                DispatchQueue.main.async { completion(.failure(OCRError.serverError)) }
                return
            }

return } var request = URLRequest(url: URL(string: endpoint)!) request.httpMethod = "POST" request.setValue("image/jpeg", forHTTPHeaderField: "Content-Type") request.setValue("application/json", forHTTPHeaderField: "Accept") request.timeoutInterval = 30 let task = URLSession.shared.uploadTask(with: request, from: imageData) { data, response, error in if let error = error { DispatchQueue.main.async { completion(.failure(error)) } return } guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode), let data = data else { DispatchQueue.main.async { completion(.failure(OCRError.serverError)) } return }

