export async function checkoutWithStripe(
  price: Price,
  redirectPath: string = '/account'
): Promise<CheckoutResponse> {
  try {
    // Get the user from Supabase auth
    const supabase = createClient();
    const {
      error,
      data: { user }
    } = await supabase.auth.getUser();

    if (error || !user) {
      console.error(error);
      throw new Error('Could not get user session.');
    }

    // Retrieve or create the customer in Stripe
    let customer: string;
    try {
      customer = await createOrRetrieveCustomer({
        uuid: user?.id || '',
        email: user?.email || ''
      });
    } catch (err) {
      console.error(err);
      throw new Error('Unable to access customer record.');
    }

    let params: Stripe.Checkout.SessionCreateParams = {
      allow_promotion_codes: true,
      billing_address_collection: 'required',
      customer,
      customer_update: {
        address: 'auto'
      },
      line_items: [
        {
          price: price.id,
          quantity: 1
        }
      ],
      cancel_url: getURL(),
      success_url: getURL(redirectPath)
    };

    console.log(
      'Trial end:',
      calculateTrialEndUnixTimestamp(price.trial_period_days)
    );
    if (price.type === 'recurring') {
      params = {
        ...params,
        mode: 'subscription',
        subscription_data: {
          trial_end: calculateTrialEndUnixTimestamp(price.trial_period_days)
        }
      };
    } else if (price.type === 'one_time') {
      params = {
        ...params,
        mode: 'payment'
      };
    }

Stripe.Checkout.SessionCreateParams = { allow_promotion_codes: true, billing_address_collection: 'required', customer, customer_update: { address: 'auto' }, line_items: [ { price: price.id, quantity: 1 } ], cancel_url: getURL(), success_url: getURL(redirectPath) }; console.log( 'Trial end:', calculateTrialEndUnixTimestamp(price.trial_period_days) ); if (price.type === 'recurring') { params = { ...params, mode: 'subscription', subscription_data: { trial_end: calculateTrialEndUnixTimestamp(price.trial_period_days) } }; } else if (price.type === 'one_time') { params = { ...params, mode: 'payment' }; }

