import { createServerClient, type CookieOptions } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { Database } from '@/types_db';

// Define a function to create a Supabase client for server-side operations
// The function takes a cookie store created with next/headers cookies as an argument
export const createClient = () => {
  const cookieStore = cookies();

  return createServerClient<Database>(
    // Pass Supabase URL and anonymous key from the environment to the client
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,

    // Define a cookies object with methods for interacting with the cookie store and pass it to the client
    {
      cookies: {
        // The get method is used to retrieve a cookie by its name
        get(name: string) {
          return cookieStore.get(name)?.value;
        },
        // The set method is used to set a cookie with a given name, value, and options
        set(name: string, value: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value, ...options });
          } catch (error) {
            // If the set method is called from a Server Component, an error may occur
            // This can be ignored if there is middleware refreshing user sessions
          }
        },
        // The remove method is used to delete a cookie by its name
        remove(name: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value: '', ...options });
          } catch (error) {
            // If the remove method is called from a Server Component, an error may occur
            // This can be ignored if there is middleware refreshing user sessions
          }
        }
      }
    }
  );
};

import { createServerClient } from "@/lib/supabase";
import { cookies } from "next/headers";
import { NextRequest, NextResponse } from "next/server";

/**
 * Auth Callback Route (OAuth Code Exchange)
 *
 * Handles OAuth callback from Supabase Auth after Magic Link/OTP verification.
 * Exchanges authorization code for session and sets secure cookies.
 *
 * Flow:
 * 1. User clicks Magic Link or enters OTP
 * 2. Supabase Auth redirects to this endpoint with code
 * 3. Exchange code for session
 * 4. Set session cookie
 * 5. Redirect to app (or error page)
 */
export async function GET(request: NextRequest) {
  const requestUrl = new URL(request.url);
  const code = requestUrl.searchParams.get("code");
  const error = requestUrl.searchParams.get("error");
  const errorDescription = requestUrl.searchParams.get("error_description");

  // Handle auth errors (e.g., expired link, invalid code)
  if (error) {
    console.error("Auth callback error:", { error, errorDescription });
    return NextResponse.redirect(
      `${requestUrl.origin}/auth/error?error=${encodeURIComponent(
        errorDescription || error
      )}`
    );
  }

  // Code is required for OAuth exchange
  if (!code) {
    console.error("Auth callback: missing code parameter");
    return NextResponse.redirect(
      `${requestUrl.origin}/auth/error?error=missing_code`
    );
  }

  try {
    const supabase = createServerClient();

    // Exchange authorization code for session
    const { data, error: exchangeError } = await supabase.auth.exchangeCodeForSession(code);

    if (exchangeError) {
      console.error("Code exchange error:", exchangeError);
      return NextResponse.redirect(
        `${requestUrl.origin}/auth/error?error=${encodeURIComponent(
          exchangeError.message
        )}`
      );
    }

    if (!data.session) {
      console.error("Code exchange: no session returned");
      return NextResponse.redirect(
        `${requestUrl.origin}/auth/error?error=no_session`
      );
    }

for OAuth exchange if (!code) { console.error("Auth callback: missing code parameter"); return NextResponse.redirect( `${requestUrl.origin}/auth/error?error=missing_code` ); } try { const supabase = createServerClient(); // Exchange authorization code for session const { data, error: exchangeError } = await supabase.auth.exchangeCodeForSession(code); if (exchangeError) { console.error("Code exchange error:", exchangeError); return NextResponse.redirect( `${requestUrl.origin}/auth/error?error=${encodeURIComponent( exchangeError.message )}` ); } if (!data.session) { console.error("Code exchange: no session returned"); return NextResponse.redirect( `${requestUrl.origin}/auth/error?error=no_session` ); }

    // Set session cookie (secure, httpOnly, sameSite)
    const response = NextResponse.redirect(`${requestUrl.origin}/dashboard`);

    response.cookies.set("sb-session", data.session.access_token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: "lax",
      maxAge: data.session.expires_in,
      path: "/",
    });

    // Optional: Set refresh token cookie
    if (data.session.refresh_token) {
      response.cookies.set("sb-refresh", data.session.refresh_token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        sameSite: "lax",
        maxAge: 60 * 60 * 24 * 7, // 7 days
        path: "/",
      });
    }

    return response;
  } catch (error) {
    console.error("Auth callback exception:", error);
    return NextResponse.redirect(
      `${requestUrl.origin}/auth/error?error=internal_error`
    );
  }
}

import { createServerClient } from "@/lib/supabase";
import { NextResponse } from "next/server";

/**
 * Auth Health Check Endpoint
 *
 * Verifies Supabase Auth connectivity and configuration.
 * Used by monitoring systems and CI smoke tests.
 *
 * Returns:
 * - 200: Auth is healthy and reachable
 * - 500: Auth is degraded or unreachable
 */
export async function GET() {
  try {
    const supabase = createServerClient();

    // Test 1: Verify Supabase client initialized
    if (!supabase) {
      return NextResponse.json(
        {
          status: "error",
          message: "Supabase client not initialized",
          timestamp: new Date().toISOString(),
        },
        { status: 500 }
      );
    }

    // Test 2: Check Auth service health
    const startTime = Date.now();
    const { data, error } = await supabase.auth.getSession();
    const latency = Date.now() - startTime;

    if (error) {
      console.error("Auth health check failed:", error);
      return NextResponse.json(
        {
          status: "degraded",
          message: error.message,
          latency_ms: latency,
          timestamp: new Date().toISOString(),
        },
        { status: 500 }
      );
    }

    // Test 3: Verify environment variables
    const envCheck = {
